    id: "oral-answer-4023",
    title: `Projected Expenditure on Government's Pursuit of Global Leadership in Growth Areas and AI-empowered Economy`,
    date: "2026-02-12",
    parliament: "15",
    type: "Oral Answers to Questions",
    speakers: ["Gerald Giam Yean Song", "Senior Minister of State for Digital Development and Information", "Tan Kiat How"],
