    id: "oral-answer-2047",
    title: `Hiring, Developing and Strengthening Singaporean Core`,
    date: "2019-09-02",
    parliament: "13",
    type: "Oral Answers to Questions",
    speakers: ["Chan Chun Sing", "Chan Chun Sing]", "Patrick Tay Teck Guan", "Pritam Singh", "[The Minister for Trade and Industry"],
