export function getDebatesByTopic(topic: AITopic): Debate[] {
  return debates.filter(d => d.topics.includes(topic));
}

export function getDebatesBySpeaker(speaker: string): Debate[] {
  return debates.filter(d =>
    d.speakers.some(s => s.toLowerCase().includes(speaker.toLowerCase()))
  );
}

export function getDebatesByYear(year: number): Debate[] {
  return debates.filter(d => d.date.startsWith(String(year)));
}

export function getAllSpeakers(): string[] {
  const speakers = new Set<string>();
  debates.forEach(d => d.speakers.forEach(s => speakers.add(s)));
  return Array.from(speakers).sort();
}

